function buildItems() {
  let current = 1;
  return moduleTopics.map((topics, moduleIndex) => ({
    ...moduleMeta[moduleIndex],
    items: topics.map(([title, when, explanation, steps, care]) => ({
      number: current++,
      category: "Técnica",
      title,
      when,
      explanation,
      steps,
      care
    }))
  }));
}

